# Reject plans that create GCP resources without required labels
package terraform.gcp.tagging

required_labels := {"team", "environment", "cost-center"}

deny[msg] {
  resource := input.resource_changes[_]
  startswith(resource.type, "google_")
  resource.change.actions[_] == "create"

  labels := object.get(resource.change.after, "labels", {})
  missing := required_labels - {k | labels[k]}
  count(missing) > 0

  msg := sprintf(
    "%s '%s' is missing required labels: %v",
    [resource.type, resource.address, missing]
  )
}
